package main

import (
	"bufio"
	"fmt"
	"log"
	"net"
	"strings"
	"sync"
	"time"
)

type Role string

const (
	RolePlayer Role = "player"
	RoleMod    Role = "mod"
	RoleAdmin  Role = "admin"
)

type Client struct {
	conn     net.Conn
	name     string
	role     Role
	addr     string
	server   *Server
	sendMu   sync.Mutex
	closed   bool
	closedMu sync.Mutex
}

type Server struct {
	mu       sync.RWMutex
	clients  map[string]*Client
	banned   map[string]time.Time
	inventory map[string][]string
}

func NewServer() *Server {
	return &Server{
		clients:  make(map[string]*Client),
		banned:   make(map[string]time.Time),
		inventory: make(map[string][]string),
	}
}

func main() {
	s := NewServer()
	ln, err := net.Listen("tcp", ":4000")
	if err != nil {
		log.Fatal(err)
	}
	log.Println("server listening on :4000")
	for {
		conn, err := ln.Accept()
		if err != nil {
			log.Println("accept error:", err)
			continue
		}
		go s.handleConn(conn)
	}
}

func (s *Server) handleConn(conn net.Conn) {
	addr := conn.RemoteAddr().String()
	if s.isBanned(addr) {
		fmt.Fprintln(conn, "connection refused: banned")
		conn.Close()
		return
	}

	reader := bufio.NewReader(conn)

	headers := map[string]string{}
	for {
		line, err := reader.ReadString('\n')
		if err != nil {
			conn.Close()
			return
		}
		line = strings.TrimSpace(line)
		if line == "" {
			break
		}
		parts := strings.SplitN(line, ":", 2)
		if len(parts) != 2 {
			fmt.Fprintln(conn, "invalid header")
			conn.Close()
			return
		}
		key := strings.ToLower(strings.TrimSpace(parts[0]))
		val := strings.TrimSpace(parts[1])
		headers[key] = val
	}

	name := headers["x-name"]
	if name == "" {
		name = addr
	}

	roleHeader := strings.ToLower(headers["x-role"])
	role := RolePlayer
	switch Role(roleHeader) {
	case RolePlayer, RoleMod, RoleAdmin:
		role = Role(roleHeader)
	default:
		role = RolePlayer
	}

	client := &Client{
		conn:   conn,
		name:   name,
		role:   role,
		addr:   addr,
		server: s,
	}

	if !s.addClient(client) {
		fmt.Fprintln(conn, "name already in use")
		conn.Close()
		return
	}

	client.send("welcome " + client.name + " role=" + string(client.role))
	s.broadcast(fmt.Sprintf("%s joined the server", client.name), client.name)

	scanner := bufio.NewScanner(reader)
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}
		if strings.HasPrefix(line, "/") {
			s.handleCommand(client, line)
		} else {
			s.broadcast(fmt.Sprintf("[%s] %s", client.name, line), "")
		}
	}

	s.removeClient(client.name)
	s.broadcast(fmt.Sprintf("%s left the server", client.name), client.name)
	client.close()
}

func (s *Server) addClient(c *Client) bool {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, exists := s.clients[c.name]; exists {
		return false
	}
	s.clients[c.name] = c
	return true
}

func (s *Server) removeClient(name string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	delete(s.clients, name)
}

func (s *Server) getClient(name string) *Client {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.clients[name]
}

func (s *Server) broadcast(msg, skip string) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for name, c := range s.clients {
		if name == skip {
			continue
		}
		c.send(msg)
	}
}

func (s *Server) isBanned(addr string) bool {
	s.mu.RLock()
	defer s.mu.RUnlock()
	until, ok := s.banned(addr)
	if !ok {
		return false
	}
	return time.Now().Before(until)
}

func (s *Server) banAddr(addr string, d time.Duration) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.banned[addr] = time.Now().Add(d)
}

func (s *Server) handleCommand(sender *Client, line string) {
	fields := strings.Fields(line)
	if len(fields) == 0 {
		return
	}

	cmd := strings.ToLower(fields[0])

	switch cmd {
	case "/kick":
		if !hasRole(sender.role, RoleMod) {
			sender.send("permission denied")
			return
		}
		if len(fields) < 2 {
			sender.send("usage: /kick <player>")
			return
		}
		target := s.getClient(fields[1])
		if target == nil {
			sender.send("player not found")
			return
		}
		target.send("you were kicked by " + sender.name)
		target.close()
		s.removeClient(target.name)
		s.broadcast(fmt.Sprintf("%s was kicked by %s", target.name, sender.name), "")

	case "/ban":
		if !hasRole(sender.role, RoleAdmin) {
			sender.send("permission denied")
			return
		}
		if len(fields) < 2 {
			sender.send("usage: /ban <player>")
			return
		}
		target := s.getClient(fields[1])
		if target == nil {
			sender.send("player not found")
			return
		}
		s.banAddr(target.addr, 24*time.Hour)
		target.send("you were banned by " + sender.name)
		target.close()
		s.removeClient(target.name)
		s.broadcast(fmt.Sprintf("%s was banned by %s", target.name, sender.name), "")

	case "/giveitems":
		if !hasRole(sender.role, RoleAdmin) {
			sender.send("permission denied")
			return
		}
		if len(fields) < 3 {
			sender.send("usage: /giveitems <player> <item1,item2,...>")
			return
		}
		targetName := fields[1]
		items := strings.Split(fields[2], ",")
		for i := range items {
			items[i] = strings.TrimSpace(items[i])
		}
		s.mu.Lock()
		s.inventory[targetName] = append(s.inventory[targetName], items...)
		s.mu.Unlock()
		if target := s.getClient(targetName); target != nil {
			target.send("you received items: " + strings.Join(items, ", "))
		}
		sender.send("items granted to " + targetName)

	case "/whoami":
		sender.send(fmt.Sprintf("name=%s role=%s addr=%s", sender.name, sender.role, sender.addr))

	default:
		sender.send("unknown command")
	}
}

func hasRole(actual, required Role) bool {
	rank := map[Role]int{
		RolePlayer: 0,
		RoleMod:    1,
		RoleAdmin:  2,
	}
	return rank[actual] >= rank[required]
}

func (c *Client) send(msg string) {
	c.closedMu.Lock()
	closed := c.closed
	c.closedMu.Unlock()
	if closed {
		return
	}
	c.sendMu.Lock()
	defer c.sendMu.Unlock()
	fmt.Fprintln(c.conn, msg)
}

func (c *Client) close() {
	c.closedMu.Lock()
	defer c.closedMu.Unlock()
	if c.closed {
		return
	}
	c.closed = true
	c.conn.Close()
}